3	import (
4		"fmt"
5		"strings"
6		"unicode"
7	)
8	
9	const (
10		providedButNotDefinedErrMsg = "flag provided but not defined: -"
11		argumentNotProvidedErrMsg   = "flag needs an argument: "
12	)
13	
14	// flagFromError tries to parse a provided flag from an error message. If the
15	// parsing fails, it returns the input error and an empty string
16	func flagFromError(err error) (string, error) {
17		errStr := err.Error()
18		trimmed := strings.TrimPrefix(errStr, providedButNotDefinedErrMsg)
19		if errStr == trimmed {
20			return "", err
21		}
22		return trimmed, nil
23	}
24	
25	func (cmd *Command) parseFlags(args Args) (Args, error) {
26		tracef("parsing flags from arguments %[1]q (cmd=%[2]q)", args, cmd.Name)
27	
28		cmd.setFlags = map[Flag]struct{}{}
29		cmd.appliedFlags = cmd.allFlags()
30	
31		tracef("walking command lineage for persistent flags (cmd=%[1]q)", cmd.Name)
32	
33		for pCmd := cmd.parent; pCmd != nil; pCmd = pCmd.parent {
34			tracef(
35				"checking ancestor command=%[1]q for persistent flags (cmd=%[2]q)",
36				pCmd.Name, cmd.Name,
37			)
38	
39			for _, fl := range pCmd.allFlags() {
40				flNames := fl.Names()
41	
42				pfl, ok := fl.(LocalFlag)
43				if !ok || pfl.IsLocal() {
44					tracef("skipping non-persistent flag %[1]q (cmd=%[2]q)", flNames, cmd.Name)
45					continue
46				}
47	
48				tracef(
49					"checking for applying persistent flag=%[1]q pCmd=%[2]q (cmd=%[3]q)",
50					flNames, pCmd.Name, cmd.Name,
51				)
52	
53				applyPersistentFlag := true
54	
55				for _, name := range flNames {
56					if cmd.lFlag(name) != nil {
57						applyPersistentFlag = false
58						break
59					}
60				}
61	
62				if !applyPersistentFlag {
63					tracef("not applying as persistent flag=%[1]q (cmd=%[2]q)", flNames, cmd.Name)
64					continue
65				}
66	
67				tracef("applying as persistent flag=%[1]q (cmd=%[2]q)", flNames, cmd.Name)
68	
69				tracef("appending to applied flags flag=%[1]q (cmd=%[2]q)", flNames, cmd.Name)
70				cmd.appliedFlags = append(cmd.appliedFlags, fl)
71			}
72		}
73	
74		tracef("parsing flags iteratively tail=%[1]q (cmd=%[2]q)", args.Tail(), cmd.Name)
75		defer tracef("done parsing flags (cmd=%[1]q)", cmd.Name)
76	
77		posArgs := []string{}
78		for rargs := args.Slice(); len(rargs) > 0; rargs = rargs[1:] {
79			tracef("rearrange:1 (cmd=%[1]q) %[2]q", cmd.Name, rargs)
80	
81			firstArg := strings.TrimSpace(rargs[0])
82			if len(firstArg) == 0 {
83				posArgs = append(posArgs, rargs[0])
84				continue
85			}
86	
87			// stop parsing once we see a "--"
88			if firstArg == "--" {
89				// In shell completion mode, preserve "--" so that completion can detect
90				// when the user is completing "--" itself vs. completing after "--"
91				if cmd.Root().shellCompletion {
92					posArgs = append(posArgs, firstArg)
93				}
94				posArgs = append(posArgs, rargs[1:]...)
95				return &stringSliceArgs{posArgs}, nil
96			}
97	
98			// Check if we've reached the Nth argument and should stop flag parsing
99			if cmd.StopOnNthArg != nil && len(posArgs) == *cmd.StopOnNthArg {
100				// Append current arg and all remaining args without parsing
101				posArgs = append(posArgs, rargs[0:]...)
102				return &stringSliceArgs{posArgs}, nil
103			}
104	
105			// handle positional args
106			if firstArg[0] != '-' {
107				// positional argument probably
108				tracef("rearrange-3 (cmd=%[1]q) check %[2]q", cmd.Name, firstArg)
109	
110				// if there is a command by that name let the command handle the
111				// rest of the parsing
112				if cmd.Command(firstArg) != nil {
113					posArgs = append(posArgs, rargs...)
114					return &stringSliceArgs{posArgs}, nil
115				}
116	
117				posArgs = append(posArgs, firstArg)
118				continue
119			}
120	
121			numMinuses := 1
122			// this is same as firstArg == "-"
123			if len(firstArg) == 1 {
124				posArgs = append(posArgs, firstArg)
125				break
126			}
127	
128			shortOptionHandling := cmd.useShortOptionHandling()
129	
130			// stop parsing -- as short flags
131			if firstArg[1] == '-' {
132				numMinuses++
133				shortOptionHandling = false
134			} else if !unicode.IsLetter(rune(firstArg[1])) {
135				// this is not a flag
136				tracef("parseFlags not a unicode letter. Stop parsing")
137				posArgs = append(posArgs, rargs...)
138				return &stringSliceArgs{posArgs}, nil
139			}
140	
141			tracef("parseFlags (shortOptionHandling=%[1]q)", shortOptionHandling)
142	
143			flagName := firstArg[numMinuses:]
144			flagVal := ""
145			valFromEqual := false
146			tracef("flagName:1 (fName=%[1]q)", flagName)
147			if index := strings.Index(flagName, "="); index != -1 {
148				flagVal = flagName[index+1:]
149				flagName = flagName[:index]
150				valFromEqual = true
151			}
152	
153			tracef("flagName:2 (fName=%[1]q) (fVal=%[2]q)", flagName, flagVal)
154	
155			f := cmd.lookupAppliedFlag(flagName)
156			// found a flag matching given flagName
157			if f != nil {
158				tracef("Trying flag type (fName=%[1]q) (type=%[2]T)", flagName, f)
159				if fb, ok := f.(boolFlag); ok && fb.IsBoolFlag() {
160					if flagVal == "" {
161						flagVal = "true"
162					}
163					tracef("parse Apply bool flag (fName=%[1]q) (fVal=%[2]q)", flagName, flagVal)
164					if err := cmd.set(flagName, f, flagVal); err != nil {
165						return &stringSliceArgs{posArgs}, err
166					}
167					continue
168				}
169	
170				tracef("processing non bool flag (fName=%[1]q)", flagName)
171				// not a bool flag so need to get the next arg
172				if flagVal == "" && !valFromEqual {
173					if len(rargs) == 1 {
174						// In shell completion mode, preserve the flag so that DefaultCompleteWithFlags can use it
175						// as lastArg and offer suggestions for it.
176						if cmd.Root().shellCompletion {
177							posArgs = append(posArgs, rargs...)
178							return &stringSliceArgs{posArgs}, nil
179						}
180						return &stringSliceArgs{posArgs}, fmt.Errorf("%s%s", argumentNotProvidedErrMsg, firstArg)
181					}
182					flagVal = rargs[1]
183					rargs = rargs[1:]
184				}
185	
186				tracef("setting non bool flag (fName=%[1]q) (fVal=%[2]q)", flagName, flagVal)
187				if err := cmd.set(flagName, f, flagVal); err != nil {
188					return &stringSliceArgs{posArgs}, err
189				}
190	
191				continue
192			}
193	
194			// no flag lookup found and short handling is disabled
195			if !shortOptionHandling {
196				// In shell completion mode, preserve the partial flag so that DefaultCompleteWithFlags can use it
197				// as lastArg and offer suggestions that match the prefix.
198				if cmd.Root().shellCompletion {
199					posArgs = append(posArgs, rargs...)
200					return &stringSliceArgs{posArgs}, nil
201				}
202				// When DefaultCommand is set, pass unknown flags through as positional args
203				// so the default command can handle them (fixes #2249)
204				if cmd.DefaultCommand != "" {
205					posArgs = append(posArgs, rargs...)
206					return &stringSliceArgs{posArgs}, nil
207				}
208				return &stringSliceArgs{posArgs}, fmt.Errorf("%s%s", providedButNotDefinedErrMsg, flagName)
209			}
210	
211			// try to split the flags
212			for index, c := range flagName {
213				tracef("processing flag (fName=%[1]q)", string(c))
214				if sf := cmd.lookupFlag(string(c)); sf == nil {
215					if index == 0 && cmd.DefaultCommand != "" {
216						posArgs = append(posArgs, rargs...)
217						return &stringSliceArgs{posArgs}, nil
218					}
219					return &stringSliceArgs{posArgs}, fmt.Errorf("%s%s", providedButNotDefinedErrMsg, flagName)
220				} else if fb, ok := sf.(boolFlag); ok && fb.IsBoolFlag() {
221					fv := flagVal
222					if index == (len(flagName)-1) && flagVal == "" {
223						fv = "true"
224					}
225					if fv == "" {
226						fv = "true"
227					}
228					if err := cmd.set(flagName, sf, fv); err != nil {
229						tracef("processing flag.2 (fName=%[1]q)", string(c))
230						return &stringSliceArgs{posArgs}, err
231					}
232				} else if index == len(flagName)-1 { // last flag can take an arg
233					if flagVal == "" {
234						if len(rargs) == 1 {
235							return &stringSliceArgs{posArgs}, fmt.Errorf("%s%s", argumentNotProvidedErrMsg, string(c))
236						}
237						flagVal = rargs[1]
238						rargs = rargs[1:]
239					}
240					tracef("parseFlags (flagName %[1]q) (flagVal %[2]q)", flagName, flagVal)
241					if err := cmd.set(flagName, sf, flagVal); err != nil {
242						tracef("processing flag.4 (fName=%[1]q)", string(c))
243						return &stringSliceArgs{posArgs}, err
244					}
245				}
246			}
247		}
248	
249		tracef("returning-2 (cmd=%[1]q) args %[2]q", cmd.Name, posArgs)
250		return &stringSliceArgs{posArgs}, nil
251	}
